#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,X,Y,A,B;
        scanf("%lld %lld %lld %lld %lld", &N, &X, &Y, &A, &B);
        long long left = X * B;   // X*B
        long long right = Y * A;  // Y*A
        if(left < right) printf("PETROL\n");
        else if(left > right) printf("DIESEL\n");
        else printf("ANY\n");
    }
    return 0;
}

